cing:-.04em}.scanner-frame{background:linear-gradient(135deg,rgba(18,18,45,.96),rgba(40,31,88,.95));border:1px solid rgba(129,140,248,.30);padding:.5rem!important}.scanner-reader{width:100%;aspect-ratio:16/9;min-height:220px;border-radius:1rem;overflow:hidden;background:#000;position:relative}.scanner-reader video,.scanner-reader canvas{width:100%!important;height:100%!important;object-fit:cover}.scanner-overlay{position:absolute;inset:0;display:grid;place-items:center;gap:.55rem;color:#fff;text-align:center;pointer-events:none;z-index:1;background:linear-gradient(180deg,rgba(17,24,39,.02),rgba(17,24,39,.12))}.scanner-overlay-badge{width:3.5rem;height:3.5rem;border-radius:999px;display:inline-flex;align-items:center;justify-content:center;font-size:1.5rem;color:#fff;background:rgba(99,102,241,.22);box-shadow:0 0 0 12px rgba(99,102,241,.08)}.lookup-grid{display:grid;grid-template-columns:minmax(0,1fr) auto minmax(0,1fr);gap:1rem;align-items:stretch}.lookup-card{padding:1.25rem;border-radius:1.25rem;border:1px solid rgba(148,163,184,.16);background:rgba(255,255,255,.72)}.lookup-divider{display:grid;place-items:center;color:#64748b;font-weight:800;letter-spacing:.08em}.lookup-divider span{width:2.6rem;height:2.6rem;border-radius:999px;display:grid;place-items:center;background:rgba(255,255,255,.92);border:1px solid rgba(148,163,184,.18)}.lookup-input .form-control{border-color:rgba(148,163,184,.25);background:rgba(255,255,255,.92)}.lookup-input .form-control:focus{box-shadow:0 0 0 .2rem rgba(99,102,241,.12)}.result-card{background:linear-gradient(180deg,rgba(255,255,255,.92),rgba(241,245,255,.84));border:1px solid rgba(99,102,241,.12)}.result-kicker{color:#6366f1;font-size:.85rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase}.result-title{color:#1f2452;font-weight:800;letter-spacing:-.03em}#result-content>div:last-child{border-bottom:0!important;padding-bottom:0!important}#result-content span:last-child{color:#111827}.history-empty{padding:2.25rem 1.5re