<script src="https://unpkg.com/html5-qrcode"></script>
<script>
(()=>{const historyKey='scan_history',scannerReader=document.getElementById('scannerReader'),scannerStatus=document.getElementById('scanner-status'),historyAlert=document.getElementById('history-alert'),resultWrap=document.getElementById('result-wrap'),resultContent=document.getElementById('result-content'),historyList=document.getElementById('history-list'),historyEmpty=document.getElementById('history-empty'),manualCode=document.getElementById('manual-code'),barcodeFile=document.getElementById('barcode-file'),startCameraBtn=document.getElementById('start-camera-btn'),stopCameraBtn=document.getElementById('stop-camera-btn'),lookupBtn=document.getElementById('lookup-btn'),scanFileBtn=document.getElementById('scan-file-btn'),clearHistoryBtn=document.getElementById('clear-history-btn'),copyResultBtn=document.getElementById('copy-result-btn');let q=null,lastText='',currentResultText='',scannerRunning=false,scanInProgress=false,flashEl=null;const getHistory=()=>{try{return JSON.parse(localStorage.getItem(historyKey)||'[]')}catch(e){return[]}};const setHistory=a=>{localStorage.setItem(historyKey,JSON.stringify(a.slice(0,20)));renderHistory()};const pushHistory=(u,t,v)=>{const a=getHistory().filter(i=>i.unique_code!==u||i.result_text!==t||i.valid!==v);a.unshift({unique_code:u,result_text:t,valid:v,timestamp:new Date().toISOString()});setHistory(a)};const renderHistory=()=>{const a=getHistory().slice(0,10);historyList.innerHTML='';historyEmpty.classList.toggle('d-none',a.length!==0);a.forEach((i,idx)=>{const row=document.createElement('div');row.className='list-group-item';row.innerHTML=`<div class="history-row p-3"><div class="d-flex flex-wrap justify-content-between align-items-center gap-3"><div><div class="fw-semibold">${i.unique_code}</div><div class="small text-secondary">${new Date(i.timestamp).toLocaleString()}</div><div class="small ${i.valid?'text-success':'text-danger'}">${i.valid?'Found':'Invalid'}</div></div><div class="d-flex gap-2"><button type="button" class="btn btn-sm btn-outline-dark" data-action="copy" data-index="${idx}">Copy</button><button type="button" class="btn btn-sm btn-outline-danger" data-action="delete" data-index="${idx}">Delete</button></div></div></div>`;historyList.appendChild(row)})};const setStatus=(m,t='info')=>scannerStatus.innerHTML=m?`<div class="alert alert-${t} mb-0">${m}</div>`:'';const setHistoryMessage=(m,t='warning')=>historyAlert.innerHTML=m?`<div class="alert alert-${t} mb-0">${m}</div>`:'';const setCameraActive=a=>{document.getElementById('cameraFrame').classList.toggle('is-active',a);document.getElementById('cameraFrame').classList.toggle('border-dashed',!a);startCameraBtn.classList.toggle('d-none',a);stopCameraBtn.classList.toggle('d-none',!a)};const qSize=()=>Math.max(180,Math.min(Math.floor((document.getElementById('cameraFrame')?.clientWidth||window.innerWidth||320)*.75),320));const flashCue=()=>{const el=flashEl||(flashEl=document.createElement('div'));if(!el.parentNode)scannerReader.appendChild(el);el.className='scanner-flash';el.classList.remove('is-visible');void el.offsetWidth;el.classList.add('is-visible')};const setResultState=ok=>{resultWrap.classList.remove('d-none');document.getElementById('resultBorder').classList.toggle('is-success',ok);document.getElementById('resultBorder').classList.toggle('is-danger',!ok);document.getElementById('invalidAlert').classList.toggle('d-none',ok)};const renderResult=d=>{const p=d.product||{},rows=[['Unique Code',d.unique_code],['Barcode Format',d.barcode_format||'N/A'],['Product Name',p.name||'N/A'],['Scanned At',d.scanned_at?new Date(d.scanned_at).toLocaleString():new Date().toLocaleString()]];currentResultText=rows.map(([l,v])=>`${l}: ${v}`).join('\n');resultContent.innerHTML=rows.map(([l,v])=>`<div class="d-flex justify-content-between gap-3 border-bottom pb-2"><span class="text-secondary">${l}</span><span class="fw-semibold text-end">${v??'N/A'}</span></div>`).join('');setResultState(true)};const notFound=u=>{currentResultText=`Unique Code: ${u}\nStatus: Invalid`;resultContent.innerHTML='';setResultState(false)};const lookup=async(code)=>{const u=(code||'').trim();if(!u){setStatus('Enter a barcode value first.','warning');return}manualCode.value=u;setStatus('Looking up barcode...','secondary');try{const res=await fetch(`/api/v1/scan/${encodeURIComponent(u)}`,{headers:{Accept:'application/json'}}),p=await res.json().catch(()=>({}));if(p.data&&p.data.valid){setStatus('Barcode found.','success');renderResult(p.data);pushHistory(u,currentResultText,true)}else{notFound(u);setStatus(p.message||'Invalid barcode - no product found.','danger');pushHistory(u,currentResultText,false)}}catch(e){notFound(u);setStatus('Something went wrong while looking up the barcode.','danger');pushHistory(u,currentResultText,false)}};const startScan=async()=>{if(scannerRunning)return;if(typeof Html5Qrcode==='undefined'){setStatus('Scanner library failed to load. Please refresh the page and try again.','danger');return}if(!q)q=new Html5Qrcode('scannerReader');try{scannerRunning=true;setCameraActive(true);setStatus('Point the camera at a barcode to scan continuously.','secondary');await q.start({facingMode:'environment'},{fps:12,qrbox:{width:qSize(),height:Math.round(qSize()*.68)},aspectRatio:1.777,disableFlip:true,rememberLastUsedCamera:true,experimentalFeatures:{useBarCodeDetectorIfSupported:true},videoConstraints:{facingMode:{ideal:'environment'},focusMode:'continuous',width:{ideal:1280},height:{ideal:720}},formatsToSupport:[Html5QrcodeSupportedFormats.CODE_128,Html5QrcodeSupportedFormats.QR_CODE,Html5QrcodeSupportedFormats.CODE_39,Html5QrcodeSupportedFormats.EAN_13]},async(decoded)=>{const u=(decoded||'').trim();if(!u||scanInProgress||u===lastText)return;scanInProgress=true;lastText=u;manualCode.value=u;try{await lookup(u)}finally{window.setTimeout(()=>{lastText=''},1200);scanInProgress=false}})}catch(e){scannerRunning=false;setCameraActive(false);setStatus(`Unable to start the scanner${e?.message?': '+e.message:''}`,'danger')}};const stopScan=async(silent=false)=>{if(q&&scannerRunning){try{await q.stop()}catch(e){}scannerRunning=false;q.clear().catch(()=>{})}setCameraActive(false);lastText='';if(!silent)setStatus('Camera stopped.','secondary')};const fileScan=async()=>{const file=barcodeFile.files[0];if(!file){setStatus('Choose an image file to scan.','warning');return}if(!q)q=new Html5Qrcode('scannerReader');try{const u=(await q.scanFile(file,true)).trim();manualCode.value=u;flashCue();await lookup(u)}catch(e){setStatus('No barcode could be read from that image.','danger')}};const copyAll=async()=>{if(!currentResultText)return;await navigator.clipboard.writeText(currentResultText);setStatus('Result copied to clipboard.','success')};startCameraBtn.addEventListener('click',startScan);stopCameraBtn.addEventListener('click',()=>stopScan());lookupBtn.addEventListener('click',()=>lookup(manualCode.value));manualCode.addEventListener('keydown',e=>{if(e.key==='Enter')lookup(manualCode.value)});scanFileBtn.addEventListener('click',fileScan);copyResultBtn.addEventListener('click',copyAll);clearHistoryBtn.addEventListener('click',()=>{localStorage.removeItem(historyKey);renderHistory();setHistoryMessage('History cleared.','secondary')});historyList.addEventListener('click',async e=>{const b=e.target.closest('button[data-action]');if(!b)return;const a=getHistory(),i=Number(b.dataset.index),it=a[i];if(!it)return;if(b.dataset.action==='copy'){await navigator.clipboard.writeText(it.result_text);setHistoryMessage('History item copied.','success')}else{a.splice(i,1);setHistory(a);setHistoryMessage('History item deleted.','secondary')}});window.addEventListener('beforeunload',()=>stopScan(true));renderHistory();setCameraActive(false)})();
</script>
@endpush
